    when 'า' then 'า — aa (long /aa/ vowel (sara aa))'
    when 'ำ' then 'ำ — am (/am/ vowel (sara am — as in น้ำ water; written as one character))'
    when 'ิ' then 'ิ — i (short /i/ vowel (sara i))'
    when 'ี' then 'ี — ii (long /ii/ vowel (sara ii))'
